import {{ Injectable }} from '@nestjs/common';
import {{ ArticleService }} from './models/article.model';
import {{ ArticleServiceRepository }} from './repositories/article.repository';

@Injectable()
export class ArticleServiceService {{
  constructor(
    private readonly repository: ArticleServiceRepository,
  ) {{}}

  async findAll(): Promise<ArticleService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<ArticleService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<ArticleService>): Promise<ArticleService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<ArticleService>): Promise<ArticleService> {{
    return this.repository.update(id, data);
  }}
}}

